    <div>
    <div id="exodia-header">
        <img src="assets/exodia-bg1.gif" alt="Stylized globe" />
    </div>
    <h1>Exodia Legacy</h1>
    <h3>Bring Together the Assembly of Power and Claim Ultimate Power.</h3>
    </div>
</header>

<main>
    <app-available-cards></app-available-cards>
    <app-user-cards></app-user-cards>
</main>
